273	// projectRunOutHours returns the hours projected until current headroom is used
274	// based on the last-24-hour slope of the bucket series. Returns 0 when the
275	// slope is non-positive, headroom is gone/unknown, or the series is too
276	// short to estimate.
277	func projectRunOutHours(buckets []agent.UsageBucket, remaining float64) float64 {
278		if len(buckets) < 2 {
279			return 0
280		}
281		// Last 24 hours of buckets; if series is bucketed in 4h blocks, that's 6
282		// buckets; 1h buckets gives 24.
283		n := 24
284		if n > len(buckets) {
285			n = len(buckets)
286		}
287		tail := buckets[len(buckets)-n:]
288		tokens := make([]float64, len(tail))
289		for i, b := range tail {
290			tokens[i] = float64(b.Tokens)
291		}
292		perBucket := agent.LinearSlope(tokens)
293		// Convert slope-per-bucket to slope-per-hour.
294		var bucketHours float64
295		if len(tail) >= 2 {
296			bucketHours = tail[1].Start.Sub(tail[0].Start).Hours()
297		}
298		if bucketHours <= 0 {
299			bucketHours = 1
300		}
301		perHour := perBucket / bucketHours
302		if perHour <= 0 {
303			return 0
304		}
305		if remaining <= 0 {
306			return 0
307		}
308		hours := remaining / perHour
309		if hours <= 0 {
310			return 0
311		}
312		return hours
313	}
