315	func sumTailTokens(buckets []agent.UsageBucket, maxBuckets int) int {
316		if maxBuckets <= 0 || len(buckets) == 0 {
317			return 0
318		}
319		if maxBuckets > len(buckets) {
320			maxBuckets = len(buckets)
321		}
322		total := 0
323		for _, b := range buckets[len(buckets)-maxBuckets:] {
324			total += b.Tokens
325		}
326		return total
327	}
