501	// quotaFromProviderInfo derives a ProviderQuota from the upstream ProviderInfo.
502	// Returns nil when no token-level ceiling is published.
503	func quotaFromProviderInfo(p agentlib.ProviderInfo) *ProviderQuota {
504		if p.Quota == nil {
505			return nil
506		}
507		return quotaFromState(p.Quota)
508	}
