// collectProfileDecisions invokes ResolveRoute for each available profile and
// collects the candidate trace. When upstream returns the typed
// no-viable-candidate error the trace is recovered via DecisionWithCandidates.
func collectProfileDecisions(ctx context.Context, svc agentlib.DdxAgent, profileFilter string) []routeStatusProfileDecisionJSON {
	if svc == nil {
		return nil
	}
	var profileNames []string
	if profileFilter != "" {
		profileNames = []string{profileFilter}
	} else {
		profiles, err := svc.ListProfiles(ctx)
		if err != nil {
			return nil
		}
		seen := map[string]struct{}{}
		for _, p := range profiles {
			if _, ok := seen[p.Name]; ok {
				continue
			}
			seen[p.Name] = struct{}{}
			profileNames = append(profileNames, p.Name)
		}
		sort.Strings(profileNames)
	}

	var out []routeStatusProfileDecisionJSON
	for _, name := range profileNames {
		entry := resolveProfileDecision(ctx, svc, name)
		out = append(out, entry)
	}
	return out
}

// resolveProfileDecision invokes ResolveRoute for one profile and returns the
// decision trace, recovering from the typed no-viable-candidate error path.
func resolveProfileDecision(ctx context.Context, svc agentlib.DdxAgent, profile string) routeStatusProfileDecisionJSON {
	entry := routeStatusProfileDecisionJSON{Profile: profile}
	dec, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{Profile: profile})

	var candidates []agentlib.RouteCandidate
	if dec != nil {
		candidates = dec.Candidates
		entry.SelectedHarness = dec.Harness
		entry.SelectedProvider = dec.Provider
		entry.SelectedModel = dec.Model
		entry.SelectedReason = dec.Reason
	}

	if err != nil {
		// Typed no-viable-candidate error: extract Rejected count.
		var noViable interface{ Error() string }
		// Use the public DecisionWithCandidates trace if available so that
		// candidates rejected before a Decision was returned still surface.
		var traced agentlib.DecisionWithCandidates
		if errors.As(err, &traced) {
			candidates = traced.RouteCandidates()
		}
		entry.Error = err.Error()
		// Heuristic: any "no viable" messaging marks the trace as no-viable;
		// the precise typed shape is the upstream NoViableCandidateError, but
		// the public surface deliberately exposes only the trace and the
		// error string so consumers stay decoupled from the internal type.
		if strings.Contains(strings.ToLower(err.Error()), "no viable") {
			entry.NoViable = true
			entry.RejectedCount = len(candidates)
		}
		_ = noViable
	}

	for _, c := range candidates {
		entry.Candidates = append(entry.Candidates, routeStatusProfileCandidateJSON{
			Harness:      c.Harness,
			Provider:     c.Provider,
			Endpoint:     c.Endpoint,
			Model:        c.Model,
			Score:        c.Score,
			Eligible:     c.Eligible,
			Reason:       c.Reason,
			FilterReason: c.FilterReason,
		})
	}
	return entry
}

// RejectionReasonsByProvider returns rejection reasons keyed by candidate
// provider name from a RouteDecision's Candidates trace. Eligible (winning or
// tie-broken) candidates are skipped. The result is intended for surfacing
// the most-recent rejection reason on a providers UI row.
func RejectionReasonsByProvider(dec *agentlib.RouteDecision) map[string]string {
	if dec == nil {
		return nil
	}
	out := make(map[string]string)
	for _, c := range dec.Candidates {
		if c.Eligible {
			continue
		}
		key := c.Provider
		if key == "" {
			key = c.Harness
		}
		if key == "" {
			continue
		}
		reason := c.Reason
		if reason == "" {
			reason = c.FilterReason
		}
		if reason == "" {
			continue
		}
		// Keep the first reason encountered for a given provider; ranking is
		// deterministic upstream so this maps to "highest-priority" rejection.
		if _, exists := out[key]; !exists {
			out[key] = reason
		}
	}
	return out
}

