// serialiseRouteCandidates produces a JSON-friendly slice of maps describing
// each evaluated route candidate. Used by appendLoopRoutingEvidence so the
// kind:routing event body carries the full decision trace, not just the
// winning pick (ddx-6036e1bc).
func serialiseRouteCandidates(cands []agentlib.RouteCandidate) []map[string]any {
	if len(cands) == 0 {
		return nil
	}
	out := make([]map[string]any, 0, len(cands))
	for _, c := range cands {
		entry := map[string]any{
			"harness":       c.Harness,
			"provider":      c.Provider,
			"endpoint":      c.Endpoint,
			"model":         c.Model,
			"score":         c.Score,
			"eligible":      c.Eligible,
			"reason":        c.Reason,
			"filter_reason": c.FilterReason,
		}
		out = append(out, entry)
	}
	return out
}

