func (r *queryResolver) ProviderStatuses(ctx context.Context) ([]*ProviderStatus, error) {
	now := time.Now().UTC()
	entries := r.sessionIndexEntries()

	rejections := defaultRouteRejectionReasons(ctx, r.WorkingDir)

	if rows := cachedProviderRows(r.WorkingDir); len(rows) > 0 {
		refreshProviderStatuses(r.WorkingDir)
		return decorateRowsWithRejections(providerRowsWithUsage(rows, entries, now), rejections), nil
	}

	if snapshots, ok, err := agent.ConfiguredProviderSnapshots(r.WorkingDir); err == nil && ok {
		rows := providerStatusesFromInfos(snapshots, entries, now)
		storeProviderRows(r.WorkingDir, rows)
		refreshProviderStatuses(r.WorkingDir)
		return decorateRowsWithRejections(rows, rejections), nil
	} else if err != nil {
		return nil, fmt.Errorf("loading provider snapshots: %w", err)
	}

	// Legacy/global provider config fallback. Bound the synchronous path so the
	// UI can still first-paint harness rows even if provider probing is slow.
	probeCtx, cancel := context.WithTimeout(ctx, 500*time.Millisecond)
	defer cancel()
	providers, err := liveProviderInfos(probeCtx, r.WorkingDir)
	if err != nil {
		refreshProviderStatuses(r.WorkingDir)
		return []*ProviderStatus{}, nil
	}
	rows := providerStatusesFromInfos(providers, entries, now)
	storeProviderRows(r.WorkingDir, rows)
	return decorateRowsWithRejections(rows, rejections), nil
}

// defaultRouteRejectionReasons resolves the default profile route via the
// upstream agentlib service and indexes rejection reasons by provider name
// from the returned RouteDecision.Candidates trace. Returns nil when routing
// is unavailable; the typed no-viable-candidate error path is recovered via
// agentlib.DecisionWithCandidates so rejection reasons surface even when no
// candidate wins (ddx-6036e1bc).
func defaultRouteRejectionReasons(ctx context.Context, workDir string) map[string]string {
	svc, err := agent.NewServiceFromWorkDir(workDir)
	if err != nil {
		return nil
	}
	dec, rerr := svc.ResolveRoute(ctx, agentlib.RouteRequest{})
	var candidates []agentlib.RouteCandidate
	if dec != nil {
		candidates = dec.Candidates
	}
	if rerr != nil {
		var traced agentlib.DecisionWithCandidates
		if errAs(rerr, &traced) {
			candidates = traced.RouteCandidates()
		}
	}
	if len(candidates) == 0 {
		return nil
	}
	out := make(map[string]string)
	for _, c := range candidates {
		if c.Eligible {
			continue
		}
		key := c.Provider
		if key == "" {
			key = c.Harness
		}
		if key == "" {
			continue
		}
		reason := c.Reason
		if reason == "" {
			reason = c.FilterReason
		}
		if reason == "" {
			continue
		}
		if _, exists := out[key]; !exists {
			out[key] = reason
		}
	}
	return out
}

// decorateRowsWithRejections appends the most-recent rejection reason from
// the default-route decision trace to each provider/harness row's Detail
// field. The UI can render this as a rejection-reason column / heatmap
// without a schema change (ddx-6036e1bc AC #3).
func decorateRowsWithRejections(rows []*ProviderStatus, rejections map[string]string) []*ProviderStatus {
	if len(rejections) == 0 {
		return rows
	}
	for _, row := range rows {
		if row == nil {
			continue
		}
		reason, ok := rejections[row.Name]
		if !ok {
			continue
		}
		marker := "rejected: " + reason
		if row.Detail == "" {
			row.Detail = marker
			continue
		}
		if !strings.Contains(row.Detail, marker) {
			row.Detail = row.Detail + " | " + marker
		}
	}
	return rows
}

