// stubAgentServiceWithProfiles extends the routing-overrides stub with
// programmable ListProfiles and RouteStatus returns so that route-status can
// be exercised end-to-end against a controlled per-profile decision trace.
type stubAgentServiceWithProfiles struct {
	stubAgentService
	profiles    []agentlib.ProfileInfo
	routeStatus *agentlib.RouteStatusReport
}

func (s *stubAgentServiceWithProfiles) ListProfiles(_ context.Context) ([]agentlib.ProfileInfo, error) {
	return s.profiles, nil
}

func (s *stubAgentServiceWithProfiles) RouteStatus(_ context.Context) (*agentlib.RouteStatusReport, error) {
	if s.routeStatus != nil {
		return s.routeStatus, nil
	}
	return &agentlib.RouteStatusReport{}, nil
}

func installStubServiceWithProfiles(t *testing.T, stub *stubAgentServiceWithProfiles) {
	t.Helper()
	SetAgentServiceFactoryForTest(func(_ string) (agentlib.DdxAgent, error) {
		return stub, nil
	})
