}

// AC #1, #5: success-path per-profile decision trace.
//
// The stub returns an eligible candidate for profile=default and an eligible
// candidate (plus two rejected ones) for profile=local. Both ResolveRoute
// calls succeed; route-status renders the full Candidates trace.
func TestAgentRouteStatusProfileDecisionTrace_Success(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	defaultDecision := &agentlib.RouteDecision{
		Harness:  "claude",
		Provider: "anthropic",
		Model:    "claude-opus-4-7",
		Reason:   "default-profile-winner",
		Candidates: []agentlib.RouteCandidate{
			{Harness: "claude", Provider: "anthropic", Model: "claude-opus-4-7", Score: 1.0, Eligible: true, Reason: "default-profile-winner"},
		},
	}
	localDecision := &agentlib.RouteDecision{
		Harness:  "agent",
		Provider: "lmstudio",
		Model:    "qwen3-32b",
		Reason:   "local-profile-winner",
		Candidates: []agentlib.RouteCandidate{
			{Harness: "agent", Provider: "lmstudio", Model: "qwen3-32b", Score: 0.9, Eligible: true, Reason: "local-profile-winner"},
			{Harness: "claude", Provider: "anthropic", Model: "claude-opus-4-7", Score: 0.0, Eligible: false, Reason: "preference is local-only", FilterReason: "unhealthy"},
			{Harness: "codex", Provider: "openai", Model: "gpt-5.4", Score: 0.0, Eligible: false, Reason: "preference is local-only", FilterReason: "unhealthy"},
		},
	}

	stub := &stubAgentServiceWithProfiles{
		stubAgentService: stubAgentService{
			resolve: func(req agentlib.RouteRequest) (*agentlib.RouteDecision, error) {
				switch req.Profile {
				case "default":
					return defaultDecision, nil
				case "local":
					return localDecision, nil
				}
				return nil, fmt.Errorf("unknown profile %q", req.Profile)
			},
		},
		profiles: []agentlib.ProfileInfo{{Name: "default"}, {Name: "local"}},
	}
	installStubServiceWithProfiles(t, stub)

	dir := minimalProjectDir(t)
	out, err := executeCommand(
		NewCommandFactory(dir).NewRootCommand(),
		"agent", "route-status", "--json",
	)
	require.NoError(t, err)

	var payload routeStatusJSON
	require.NoError(t, json.Unmarshal([]byte(out), &payload))
	require.Len(t, payload.ProfileDecisions, 2,
		"per-profile decision trace must emit one entry per profile")

	byName := map[string]routeStatusProfileDecisionJSON{}
	for _, pd := range payload.ProfileDecisions {
		byName[pd.Profile] = pd
	}
	def := byName["default"]
	assert.Equal(t, "claude", def.SelectedHarness)
	assert.Equal(t, "anthropic", def.SelectedProvider)
	assert.Equal(t, "claude-opus-4-7", def.SelectedModel)
	assert.Len(t, def.Candidates, 1)
	assert.True(t, def.Candidates[0].Eligible)

	loc := byName["local"]
	assert.Equal(t, "agent", loc.SelectedHarness)
	require.Len(t, loc.Candidates, 3)
	// Rejected candidates carry their reason and filter_reason from upstream.
	rejected := 0
	for _, c := range loc.Candidates {
		if !c.Eligible {
			rejected++
			assert.Equal(t, "preference is local-only", c.Reason,
				"rejected candidate must surface upstream Reason verbatim")
			assert.Equal(t, "unhealthy", c.FilterReason)
		}
	}
	assert.Equal(t, 2, rejected, "two rejected candidates expected for local")
}

// AC #2, #5: typed no-viable-candidate error path.
//
// ResolveRoute returns a *DecisionWithCandidates-bearing error. route-status
// recovers the candidate trace via errors.As and renders the rejection
// heatmap (each candidate's reason / filter_reason).
func TestAgentRouteStatusProfileDecisionTrace_NoViableCandidate(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	rejected := []agentlib.RouteCandidate{
		{Harness: "agent", Provider: "lmstudio", Model: "qwen3-32b", Eligible: false, Reason: "no live provider", FilterReason: "unhealthy"},
		{Harness: "claude", Provider: "anthropic", Model: "claude-opus-4-7", Eligible: false, Reason: "subscription quota exhausted", FilterReason: "unhealthy"},
	}
	noViable := &fakeDecisionErr{
		msg:        "no viable routing candidate: 2 candidates rejected",
		candidates: rejected,
	}

	stub := &stubAgentServiceWithProfiles{
		stubAgentService: stubAgentService{
			resolve: func(req agentlib.RouteRequest) (*agentlib.RouteDecision, error) {
				return &agentlib.RouteDecision{Candidates: rejected}, noViable
			},
		},
		profiles: []agentlib.ProfileInfo{{Name: "default"}},
	}
	installStubServiceWithProfiles(t, stub)

	dir := minimalProjectDir(t)
	out, err := executeCommand(
		NewCommandFactory(dir).NewRootCommand(),
		"agent", "route-status", "--json",
	)
	require.NoError(t, err)

	var payload routeStatusJSON
	require.NoError(t, json.Unmarshal([]byte(out), &payload))
	require.Len(t, payload.ProfileDecisions, 1)

	pd := payload.ProfileDecisions[0]
	assert.True(t, pd.NoViable, "no_viable flag must be set on the typed error path")
	assert.Equal(t, 2, pd.RejectedCount, "rejected_count derived from trace length")
	assert.Equal(t, "no viable routing candidate: 2 candidates rejected", pd.Error)
	require.Len(t, pd.Candidates, 2)
	assert.Equal(t, "no live provider", pd.Candidates[0].Reason)
	assert.Equal(t, "unhealthy", pd.Candidates[0].FilterReason)
	assert.Equal(t, "subscription quota exhausted", pd.Candidates[1].Reason)
}

// AC #2, #5: rendered text output also contains the rejection heatmap.
func TestAgentRouteStatusProfileDecisionTrace_TextRender(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

