// AC #2: --profile flag restricts the trace to one profile.
func TestAgentRouteStatusProfileDecisionTrace_ProfileFlag(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	var seen []string
	stub := &stubAgentServiceWithProfiles{
		stubAgentService: stubAgentService{
			resolve: func(req agentlib.RouteRequest) (*agentlib.RouteDecision, error) {
				seen = append(seen, req.Profile)
				return &agentlib.RouteDecision{Harness: "agent", Model: "x"}, nil
			},
		},
		// profiles list intentionally has more than one — the --profile flag
		// must restrict the actual ResolveRoute calls.
		profiles: []agentlib.ProfileInfo{{Name: "default"}, {Name: "local"}, {Name: "smart"}},
	}
	installStubServiceWithProfiles(t, stub)

	dir := minimalProjectDir(t)
	_, err := executeCommand(
		NewCommandFactory(dir).NewRootCommand(),
		"agent", "route-status", "--profile", "local",
	)
	require.NoError(t, err)

	require.Len(t, seen, 1, "--profile must restrict ResolveRoute to a single profile")
	assert.Equal(t, "local", seen[0])
}

// AC #3, #5: rejection-reason rendering — RejectionReasonsByProvider
// surfaces the per-provider rejection reason from a RouteDecision.Candidates
// trace, which the providers UI consumes.
func TestRejectionReasonsByProvider(t *testing.T) {
	dec := &agentlib.RouteDecision{
		Candidates: []agentlib.RouteCandidate{
			{Harness: "agent", Provider: "lmstudio", Eligible: true, Reason: "local-winner"},
			{Harness: "claude", Provider: "anthropic", Eligible: false, Reason: "subscription quota exhausted", FilterReason: "unhealthy"},
			{Harness: "codex", Provider: "openai", Eligible: false, Reason: "", FilterReason: "no_tool_support"},
		},
	}
	got := RejectionReasonsByProvider(dec)
	assert.NotContains(t, got, "lmstudio", "eligible candidates must not appear")
	assert.Equal(t, "subscription quota exhausted", got["anthropic"])
	assert.Equal(t, "no_tool_support", got["openai"], "FilterReason fallback must apply when Reason empty")

	assert.Nil(t, RejectionReasonsByProvider(nil))
	assert.Empty(t, RejectionReasonsByProvider(&agentlib.RouteDecision{}))
}

// fakeDecisionErr emulates the upstream routeDecisionError shape: it carries
// a message and exposes RouteCandidates() so consumers can extract the trace
// via errors.As against agentlib.DecisionWithCandidates.
type fakeDecisionErr struct {
	msg        string
	candidates []agentlib.RouteCandidate
}

func (e *fakeDecisionErr) Error() string                            { return e.msg }
func (e *fakeDecisionErr) RouteCandidates() []agentlib.RouteCandidate { return append([]agentlib.RouteCandidate(nil), e.candidates...) }

// Compile-time assertion: the fake satisfies the public DecisionWithCandidates
// interface so errors.As recovers the trace.
var _ agentlib.DecisionWithCandidates = (*fakeDecisionErr)(nil)

// Ensure errors.As path the command uses works against a wrapped fake.
func TestFakeDecisionErrSatisfiesDecisionWithCandidates(t *testing.T) {
	wrapped := fmt.Errorf("wrap: %w", &fakeDecisionErr{msg: "x", candidates: []agentlib.RouteCandidate{{Provider: "p"}}})
	var trace agentlib.DecisionWithCandidates
	require.True(t, errors.As(wrapped, &trace))
	require.Len(t, trace.RouteCandidates(), 1)
	assert.Equal(t, "p", trace.RouteCandidates()[0].Provider)
	_ = strings.TrimSpace
}

