package graphql

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

// AC #3, #5: rejection-reason rendering — decorateRowsWithRejections
// surfaces per-provider rejection reasons (sourced from a RouteDecision's
// Candidates trace) on the matching ProviderStatus.Detail field, so the
// providers UI can render a rejection-reason column / heatmap. ddx-6036e1bc.
func TestDecorateRowsWithRejections_AppendsReasonToMatchingRow(t *testing.T) {
	rows := []*ProviderStatus{
		{Name: "anthropic", Detail: "connected"},
		{Name: "openai", Detail: ""},
		{Name: "lmstudio", Detail: "connected"},
	}
	rejections := map[string]string{
		"anthropic": "subscription quota exhausted",
		"openai":    "no_tool_support",
		// lmstudio has no rejection — it was the winning candidate.
	}

	got := decorateRowsWithRejections(rows, rejections)
	require.Equal(t, 3, len(got))

	byName := map[string]*ProviderStatus{}
	for _, r := range got {
		byName[r.Name] = r
	}
	assert.Contains(t, byName["anthropic"].Detail, "rejected: subscription quota exhausted")
	// Pre-existing detail content is preserved.
	assert.Contains(t, byName["anthropic"].Detail, "connected")
	// Empty Detail gets replaced cleanly.
	assert.Equal(t, "rejected: no_tool_support", byName["openai"].Detail)
	// Non-rejected row is untouched.
	assert.Equal(t, "connected", byName["lmstudio"].Detail)
}

func TestDecorateRowsWithRejections_NilOrEmptyMap(t *testing.T) {
	rows := []*ProviderStatus{{Name: "x", Detail: "ok"}}
	assert.Equal(t, rows, decorateRowsWithRejections(rows, nil))
	assert.Equal(t, rows, decorateRowsWithRejections(rows, map[string]string{}))
}

func TestDecorateRowsWithRejections_IsIdempotent(t *testing.T) {
	rows := []*ProviderStatus{{Name: "anthropic", Detail: "connected"}}
	rej := map[string]string{"anthropic": "subscription quota exhausted"}

	once := decorateRowsWithRejections(rows, rej)
	twice := decorateRowsWithRejections(once, rej)
	// Decorating an already-decorated row must not duplicate the marker.
	assert.Equal(t, once[0].Detail, twice[0].Detail)
}
